**(b) Given two sparse matrices A and B, write the C code and trace it with a sample input. (7 marks)**

**Model Solution:**

```c
#include <stdio.h>
#define MAX 50

void readMatrix(int mat[][3], const char *name) {
    printf("Enter %s (rows cols non-zero-count): ", name);
    scanf("%d %d %d", &mat[0][0], &mat[0][1], &mat[0][2]);
    printf("Enter %d elements (row col val):\n", mat[0][2]);
    for (int i = 1; i <= mat[0][2]; i++) {
        scanf("%d %d %d", &mat[i][0], &mat[i][1], &mat[i][2]);
    }
}

void addMatrices(int A[][3], int B[][3], int C[][3]) {
    if (A[0][0] != B[0][0] || A[0][1] != B[0][1]) {
        printf("Error: Dimension mismatch.\n");
        C[0][2] = 0;
        return;
    }
    C[0][0] = A[0][0]; C[0][1] = A[0][1];
    int i = 1, j = 1, k = 1, sum;
    while (i <= A[0][2] && j <= B[0][2]) {
        if (A[i][0] < B[j][0] || 
           (A[i][0] == B[j][0] && A[i][1] < B[j][1])) {
            C[k][0] = A[i][0]; C[k][1] = A[i][1]; C[k][2] = A[i][2];
            i++; k++;
        } else if (A[i][0] == B[j][0] && A[i][1] == B[j][1]) {
            sum = A[i][2] + B[j][2];
            if (sum != 0) { C[k][0] = A[i][0]; C[k][1] = A[i][1]; C[k][2] = sum; k++; }
            i++; j++;
        } else {
            C[k][0] = B[j][0]; C[k][1] = B[j][1]; C[k][2] = B[j][2];
            j++; k++;
        }
    }
    while (i <= A[0][2]) { C[k][0] = A[i][0]; C[k][1] = A[i][1]; C[k][2] = A[i][2]; i++; k++; }
    while (j <= B[0][2]) { C[k][0] = B[j][0]; C[k][1] = B[j][1]; C[k][2] = B[j][2]; j++; k++; }
    C[0][2] = k - 1;
}

int main() {
    int A[MAX][3], B[MAX][3], C[MAX][3];
    readMatrix(A, "Matrix A");
    readMatrix(B, "Matrix B");
    addMatrices(A, B, C);
    printf("Sum matrix C (triplet form):\n");
    for (int i = 0; i <= C[0][2]; i++) {
        printf("%d\t%d\t%d\n", C[i][0], C[i][1], C[i][2]);
    }
    return 0;
}
```

**Sample Trace:**

Input:
```
Matrix A: 3 3 2
  0 1 4
  2 2 3
Matrix B: 3 3 3
  0 0 5
  0 1 2
  2 2 7
```

Trace Steps:
- Compare $(0,1,4)$ vs $(0,0,5)$: $B$ is smaller → copy $(0,0,5)$ to $C$.
- Compare $(0,1,4)$ vs $(0,1,2)$: positions match → sum $= 4+2 = 6$ → store $(0,1,6)$ in $C$.
- Compare $(2,2,3)$ vs $(2,2,7)$: positions match → sum $= 3+7 = 10$ → store $(2,2,10)$ in $C$.

Output:
```
3 3 3
0 0 5
0 1 6
2 2 10
```

