### 3.3 Exhaustive C Implementation — Deque (Double-Ended Queue)

```c
#include <stdio.h>
#define MAX 5

int dq[MAX];
int front = -1, rear = -1;

void insertRear(int x) {
    if ((rear + 1) % MAX == front) {
        printf("Deque Full\n"); return;
    }
    if (front == -1)
        front = rear = 0;
    else
        rear = (rear + 1) % MAX;
    dq[rear] = x;
    printf("%d inserted at rear\n", x);
}

void insertFront(int x) {
    if ((rear + 1) % MAX == front || front == 0 && rear == MAX-1) {
        printf("Deque Full\n"); return;
    }
    if (front == -1)
        front = rear = 0;
    else if (front == 0)
        front = MAX - 1;
    else
        front--;
    dq[front] = x;
    printf("%d inserted at front\n", x);
}

int deleteFront() {
    if (front == -1) {
        printf("Deque Empty\n"); return -1;
    }
    int item = dq[front];
    if (front == rear)
        front = rear = -1;
    else
        front = (front + 1) % MAX;
    printf("%d deleted from front\n", item);
    return item;
}

int deleteRear() {
    if (front == -1) {
        printf("Deque Empty\n"); return -1;
    }
    int item = dq[rear];
    if (front == rear)
        front = rear = -1;
    else if (rear == 0)
        rear = MAX - 1;
    else
        rear--;
    printf("%d deleted from rear\n", item);
    return item;
}

void display() {
    if (front == -1) { printf("Empty\n"); return; }
    int i = front;
    printf("Deque: ");
    while (1) {
        printf("%d ", dq[i]);
        if (i == rear) break;
        i = (i + 1) % MAX;
    }
    printf("\n");
}

int main() {
    insertRear(10);
    insertRear(20);
    insertFront(5);
    display();
    deleteRear();
    deleteFront();
    display();
    return 0;
}
```

**Step-by-Step Trace (MAX = 5):**

| Step | Operation | front | rear | State |
| :--- | :--- | :--- | :--- | :--- |
| 0 | Initial | -1 | -1 | Empty |
| 1 | `insertRear(10)` | 0 | 0 | [10, _, _, _, _] |
| 2 | `insertRear(20)` | 0 | 1 | [10, 20, _, _, _] |
| 3 | `insertFront(5)` | 4 | 1 | [10, 20, _, _, 5] — wrapped backward |
| 4 | `deleteRear()` | 4 | 0 | [10, _, _, _, 5] |
| 5 | `deleteFront()` | 0 | 0 | [10, _, _, _, _] |

**Derivation of "backward wrap" for insertFront:**

$$
front_{new} = (front_{old} - 1 + MAX) \bmod MAX
$$

The expression `(front - 1 + MAX)` guarantees the value is **non-negative** before applying `% MAX`. In C, the `%` operator on a negative number returns a negative result, which would corrupt the index. Always add `MAX` first!

$$
\begin{aligned}
\text{Example: } front_{old} &= 0,\ MAX = 5 \\
front_{new} &= (0 - 1 + 5) \bmod 5 = 4 \bmod 5 = 4 \quad \checkmark
\end{aligned}
$$
