#### **Question B (14 Marks) `[KTU University Exam - Jun 2024]`**

**(a) Write a complete C program to implement a Double-Ended Queue (Deque) using an array of size 6, supporting the operations: insertFront, insertRear, deleteFront, deleteRear, and display. (8 Marks)**

**Solution:**

```c
#include <stdio.h>
#define MAX 6

int dq[MAX];
int front = -1, rear = -1;

void insertRear(int x) {
    if ((rear + 1) % MAX == front) {
        printf("Deque Full\n"); return;
    }
    if (front == -1)
        front = rear = 0;
    else
        rear = (rear + 1) % MAX;
    dq[rear] = x;
}

void insertFront(int x) {
    if ((rear + 1) % MAX == front) {
        printf("Deque Full\n"); return;
    }
    if (front == -1)
        front = rear = 0;
    else if (front == 0)
        front = MAX - 1;
    else
        front--;
    dq[front] = x;
}

void deleteFront() {
    if (front == -1) { printf("Empty\n"); return; }
    printf("%d deleted\n", dq[front]);
    if (front == rear) front = rear = -1;
    else front = (front + 1) % MAX;
}

void deleteRear() {
    if (front == -1) { printf("Empty\n"); return; }
    printf("%d deleted\n", dq[rear]);
    if (front == rear) front = rear = -1;
    else if (rear == 0) rear = MAX - 1;
    else rear--;
}

void display() {
    if (front == -1) { printf("Empty\n"); return; }
    int i = front;
    while (1) {
        printf("%d ", dq[i]);
        if (i == rear) break;
        i = (i + 1) % MAX;
    }
    printf("\n");
}

int main() {
    insertRear(10); insertRear(20);
    insertFront(5);
    display();
    deleteRear();
    deleteFront();
    display();
    return 0;
}
```

