# Section 3: Step-by-Step Derivations & Analytical Matrix

## 3.1 The Complete C Implementation (Algorithm Walkthrough)

Below is the **full, executable C program** that satisfies the KTU 2024 lab record requirements. Every line is annotated for the analytical matrix.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* ===========================================================
 *  PageNode : Doubly Linked List node for browser history
 * =========================================================== */
typedef struct PageNode {
    char url[100];
    struct PageNode *prev;
    struct PageNode *next;
} PageNode;

/* Global head and current pointers */
PageNode *head    = NULL;
PageNode *current = NULL;

/* ---------- Helper: Create and initialize a new node ---------- */
PageNode* createNode(char *url) {
    PageNode *newNode = (PageNode *)malloc(sizeof(PageNode));
    if (newNode == NULL) {
        printf("Memory allocation failed.\n");
        exit(1);
    }
    strcpy(newNode->url, url);
    newNode->prev = NULL;
    newNode->next = NULL;
    return newNode;
}

/* ---------- Operation 1: Visit a new page ---------- */
void visitPage(char *url) {
    /* Step 1: Invalidate forward history if any */
    if (current != NULL && current->next != NULL) {
        PageNode *temp = current->next;
        while (temp != NULL) {
            PageNode *toDelete = temp;
            temp = temp->next;
            free(toDelete);
        }
        current->next = NULL;   /* Sever forward link */
    }

    /* Step 2: Create the new node */
    PageNode *newNode = createNode(url);

    /* Step 3: Insert at the appropriate position */
    if (head == NULL) {
        head = newNode;
    } else {
        newNode->prev = current;
        current->next = newNode;
    }
    current = newNode;          /* Move current to new page */

    printf("Visited: %s\n", current->url);
}

/* ---------- Operation 2: Go back ---------- */
void goBack() {
    if (current == NULL || current->prev == NULL) {
        printf("No previous page in history.\n");
        return;
    }
    current = current->prev;
    printf("Navigated BACK to: %s\n", current->url);
}

/* ---------- Operation 3: Go forward ---------- */
void goForward() {
    if (current == NULL || current->next == NULL) {
        printf("No forward page in history.\n");
        return;
    }
    current = current->next;
    printf("Navigated FORWARD to: %s\n", current->url);
}

/* ---------- Operation 4: Display full history ---------- */
void displayHistory() {
    if (head == NULL) {
        printf("No pages visited yet.\n");
        return;
    }
    PageNode *temp = head;
    int idx = 1;
    printf("\n------- Browser History -------\n");
    while (temp != NULL) {
        if (temp == current) {
            printf("-> [CURRENT] %d. %s\n", idx, temp->url);
        } else {
            printf("   %2d. %s\n", idx, temp->url);
        }
        temp = temp->next;
        idx++;
    }
    printf("-------------------------------\n");
}

/* ---------- Cleanup: free all allocated memory ---------- */
void freeAll() {
    PageNode *temp = head;
    while (temp != NULL) {
        PageNode *next = temp->next;
        free(temp);
        temp = next;
    }
    head = current = NULL;
}

/* ---------- Main: menu-driven driver ---------- */
int main() {
    int choice;
    char url[100];

    while (1) {
        printf("\n===== Browser Navigation Menu =====\n");
        printf("1. Visit New Page\n");
        printf("2. Go Back\n");
        printf("3. Go Forward\n");
        printf("4. Display History\n");
        printf("5. Exit\n");
        printf("Enter your choice: ");
        scanf("%d", &choice);
        getchar();  /* consume trailing newline */

        switch (choice) {
            case 1:
                printf("Enter URL: ");
                fgets(url, sizeof(url), stdin);
                url[strcspn(url, "\n")] = '\0';
                visitPage(url);
                break;
            case 2:
                goBack();
                break;
            case 3:
                goForward();
                break;
            case 4:
                displayHistory();
                break;
            case 5:
                freeAll();
                printf("Exiting browser simulation.\n");
                exit(0);
            default:
                printf("Invalid choice! Try again.\n");
        }
    }
    return 0;
}
```

