## 3. Step-by-Step Derivations & Analytical Matrix

### 3.1 Complete C Program — Lab-Ready Implementation

```c
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// ─────────────── Node Definition ───────────────
struct Node {
    int coeff;
    int exp;
    struct Node* next;
};
typedef struct Node Node;

// ─────────────── Create a new node ───────────────
Node* createNode(int c, int e) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->coeff = c;
    n->exp   = e;
    n->next  = NULL;
    return n;
}

// ─────────────── Append a term at the end ───────────────
Node* append(Node* head, int c, int e) {
    Node* n = createNode(c, e);
    if (head == NULL) return n;
    Node* t = head;
    while (t->next != NULL) t = t->next;
    t->next = n;
    return head;
}

// ─────────────── Read polynomial from user ───────────────
Node* readPoly(const char* name) {
    Node* head = NULL;
    int n, c, e;
    printf("\nEnter number of terms in %s : ", name);
    scanf("%d", &n);
    for (int i = 0; i < n; i++) {
        printf("  Term %d -> coefficient & exponent : ", i + 1);
        scanf("%d %d", &c, &e);
        head = append(head, c, e);
    }
    return head;
}

// ─────────────── Display polynomial ───────────────
void display(Node* head) {
    if (head == NULL) { printf("0\n"); return; }
    Node* t = head;
    int first = 1;
    while (t != NULL) {
        int c = t->coeff, e = t->exp;
        if (!first && c > 0) printf(" + ");
        if (first && c < 0)  printf("-");
        if (!first && c < 0) printf(" - ");
        printf("%d", abs(c));
        if (e != 0) printf("x^%d", e);
        first = 0;
        t = t->next;
    }
    printf("\n");
}

// ─────────────── Polynomial ADDITION ───────────────
Node* addPoly(Node* p1, Node* p2) {
    Node* res = NULL;
    while (p1 != NULL && p2 != NULL) {
        if (p1->exp > p2->exp) {
            res = append(res, p1->coeff, p1->exp);
            p1 = p1->next;
        } else if (p1->exp < p2->exp) {
            res = append(res, p2->coeff, p2->exp);
            p2 = p2->next;
        } else {
            int s = p1->coeff + p2->coeff;
            if (s != 0) res = append(res, s, p1->exp);
            p1 = p1->next; p2 = p2->next;
        }
    }
    while (p1 != NULL) { res = append(res, p1->coeff, p1->exp); p1 = p1->next; }
    while (p2 != NULL) { res = append(res, p2->coeff, p2->exp); p2 = p2->next; }
    return res;
}

// ─────────────── Polynomial MULTIPLICATION ───────────────
Node* multiplyPoly(Node* p1, Node* p2) {
    Node* res = NULL;
    for (Node* i = p1; i != NULL; i = i->next) {
        Node* temp = NULL;
        for (Node* j = p2; j != NULL; j = j->next) {
            temp = append(temp, i->coeff * j->coeff, i->exp + j->exp);
        }
        res = addPoly(res, temp);
    }
    return res;
}

// ─────────────── Driver ───────────────
int main() {
    Node *P, *Q, *R;
    P = readPoly("P(x)");
    Q = readPoly("Q(x)");
    printf("\nP(x) = "); display(P);
    printf("Q(x) = "); display(Q);

    R = addPoly(P, Q);
    printf("\nP(x) + Q(x) = "); display(R);

    R = multiplyPoly(P, Q);
    printf("P(x) * Q(x) = "); display(R);
    return 0;
}
```

### 3.2 Exhaustive Dry-Run — Worked Example (KTU Board Style)

Let us trace the algorithm with:

$$P(x) = 5x^4 + 3x^2 + 1, \quad Q(x) = 4x^3 + 2x^2 + 6$$

#### Addition Trace: $R(x) = P(x) + Q(x)$

| Step | p1→(c, e) | p2→(c, e) | Action | Result List | Advance |
|:----:|:---------:|:---------:|:-------|:------------|:--------|
| 1 | (5, **4**) | (4, **3**) | 4 > 3 → copy (5, 4) | 5x^4 | p1++ |
| 2 | (3, **2**) | (4, **3**) | 3 > 2 → copy (4, 3) | 5x^4 + 4x^3 | p2++ |
| 3 | (3, **2**) | (2, **2**) | 2 == 2 → sum = 5 | 5x^4 + 4x^3 + 5x^2 | p1++, p2++ |
| 4 | (1, **0**) | (6, **0**) | 0 == 0 → sum = 7 | 5x^4 + 4x^3 + 5x^2 + 7 | p1++, p2++ |
| 5 | NULL | NULL | Both exhausted → STOP | — | — |

$$\boxed{R(x) = 5x^4 + 4x^3 + 5x^2 + 7}$$

#### Multiplication Trace: $R(x) = P(x) \times Q(x)$

**Iteration 1:** $i = (5, 4)$ — multiply with every term of $Q(x)$:

$$\text{temp}_1 = 20x^7 + 10x^6 + 30x^4$$

**Iteration 2:** $i = (3, 2)$:

$$\text{temp}_2 = 12x^5 + 6x^4 + 18x^2$$

**Iteration 3:** $i = (1, 0)$:

$$\text{temp}_3 = 4x^3 + 2x^2 + 6$$

**Cumulative Addition:**

$$R(x) = 20x^7 + 10x^6 + (30+6)x^4 + 12x^5 + 4x^3 + (18+2)x^2 + 6$$

$$\boxed{R(x) = 20x^7 + 10x^6 + 12x^5 + 36x^4 + 4x^3 + 20x^2 + 6}$$

### 3.3 Mathematical Verification (Polynomial Form)

$$P(x) \cdot Q(x) = (5x^4 + 3x^2 + 1)(4x^3 + 2x^2 + 6)$$

$$\begin{aligned}
&= 5x^4(4x^3 + 2x^2 + 6) \\
&\quad + 3x^2(4x^3 + 2x^2 + 6) \\
&\quad + 1(4x^3 + 2x^2 + 6) \\
&= 20x^7 + 10x^6 + 30x^4 + 12x^5 + 6x^4 + 18x^2 + 4x^3 + 2x^2 + 6
\end{aligned}$$

Grouping like terms:

$$= 20x^7 + 10x^6 + 12x^5 + (30+6)x^4 + 4x^3 + (18+2)x^2 + 6$$

$$= 20x^7 + 10x^6 + 12x^5 + 36x^4 + 4x^3 + 20x^2 + 6 \;\checkmark$$

The C program output matches the manual expansion **exactly** — confirming correctness.
